export function nextGeneration(currentGeneration: Cell[]): Cell[] {
  const liveKeys = new Set(currentGeneration.map(cellKey));
  const neighbors = new Map<string, { cell: Cell; liveNeighborCount: number }>();

  for (const [x, y] of currentGeneration) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const cell: Cell = [x + dx, y + dy];
      const key = cellKey(cell);
      const entry = neighbors.get(key);
      if (entry) entry.liveNeighborCount++;
      else neighbors.set(key, { cell, liveNeighborCount: 1 });
    }
  }

  const survives = (key: string, liveNeighborCount: number): boolean =>
    liveNeighborCount === 3 || (liveNeighborCount === 2 && liveKeys.has(key));

  const next: Cell[] = [];
  for (const [key, { cell, liveNeighborCount }] of neighbors) {
    if (survives(key, liveNeighborCount)) next.push(cell);
  }
  return next;
}
